def playstartupsound():
    def _play():
        try:
            if not WINSOUND_OK or not sys.platform.startswith("win"): return
            wav_bytes = base64.b64decode(STARTUP_WAV_B64)
            winsound.PlaySound(wav_bytes, winsound.SND_MEMORY)
        except Exception as e: print("Sound error:", e)
    import threading as _th
    _th.Thread(target=_play, daemon=True).start()

# ── Windows Startup Registry helpers ─────────────────────────────────────────
_STARTUP_REG_KEY  = r"Software\Microsoft\Windows\CurrentVersion\Run"
_STARTUP_REG_NAME = "RavenMinerHQ"

def _get_startup_exe_path() -> str:
    """Return the quoted command-line string to store in the registry."""
    if getattr(sys, "frozen", False):          # PyInstaller .exe
        return f'"{sys.executable}"'
    # Running as .py — use pythonw.exe to suppress the console window
    pythonw = sys.executable.replace("python.exe", "pythonw.exe")
    script  = os.path.abspath(__file__)
    return f'"{pythonw}" "{script}"'

def get_startup_enabled() -> bool:
    """Return True if RavenMinerHQ is present in HKCU Run key."""
    try:
        import winreg
        with winreg.OpenKey(winreg.HKEY_CURRENT_USER, _STARTUP_REG_KEY) as k:
            winreg.QueryValueEx(k, _STARTUP_REG_NAME)
            return True
    except OSError:
        return False

def set_startup_enabled(enabled: bool) -> bool:
    """Write or delete the HKCU Run entry.  Returns True on success."""
    try:
        import winreg
        with winreg.OpenKey(winreg.HKEY_CURRENT_USER, _STARTUP_REG_KEY,
                            0, winreg.KEY_SET_VALUE) as k:
            if enabled:
                winreg.SetValueEx(k, _STARTUP_REG_NAME, 0,
                                  winreg.REG_SZ, _get_startup_exe_path())
            else:
                try:
                    winreg.DeleteValue(k, _STARTUP_REG_NAME)
                except FileNotFoundError:
                    pass
        return True
    except Exception as _e:
        logging.getLogger(__name__).warning("Startup registry: %s", _e)
        return False
