_alert_cfg_global_cache = None  # v3.9.3: module-level alert config cache

_NTFY_COOLDOWN        = 60          # seconds between identical alerts (in-session)
_NTFY_PERSIST_WINDOW  = 86400       # 24 h — entries older than this are pruned from disk
_ntfy_last_sent_lock  = threading.Lock()

def _get_ntfy_sent_path():
    """Same directory as ravenminer_config.json."""
    if getattr(sys, "frozen", False):
        base = os.path.dirname(sys.executable)
    else:
        base = os.path.dirname(os.path.abspath(__file__))
    return os.path.join(base, "ravenminer_ntfy_sent.json")

def _load_ntfy_sent():
    """Load persisted send-times, pruning entries older than _NTFY_PERSIST_WINDOW."""
    try:
        with open(_get_ntfy_sent_path(), "r", encoding="utf-8") as _f:
            raw = json.load(_f)
        cutoff = time.time() - _NTFY_PERSIST_WINDOW
        return {k: v for k, v in raw.items() if v > cutoff}
    except Exception:
        return {}

def _save_ntfy_sent(data):
    """Write current send-times to disk (best-effort)."""
    try:
        with open(_get_ntfy_sent_path(), "w", encoding="utf-8") as _f:
            json.dump(data, _f, indent=2)
    except Exception as _e:
        print("[RavenMiner] ntfy_sent save error:", _e)

# Loaded once at startup; pruned entries older than 24 h are already removed
_ntfy_last_sent = _load_ntfy_sent()

def send_ntfy_alert(topic_url, title, message, priority="default", tags="bell"):
    """Push notification via ntfy.sh or self-hosted ntfy server.
    topic_url: full URL e.g. https://ntfy.sh/my-topic  OR  bare topic name.
    Fixes v5.2.3:
      - Auto-normalise URL  (bare topic -> https://ntfy.sh/topic)
      - Check HTTP status code (4xx/5xx were silently swallowed before)
    """
    if not topic_url: return
    _now = time.time()  # CR2-PERF-7: removed redundant `import time as _t2`
    with _ntfy_last_sent_lock:
        if _now - _ntfy_last_sent.get(title, 0) < _NTFY_COOLDOWN:
            return
        _ntfy_last_sent[title] = _now
        _snapshot = dict(_ntfy_last_sent)  # PERF-FIX-9: snapshot inside lock, write outside
    _save_ntfy_sent(_snapshot)   # persist so restarts remember — now outside lock
    # ── URL normalisation ────────────────────────────────────────────────────
    _url = topic_url.strip()
    if not _url.startswith(("http://", "https://")):
        _url = "https://ntfy.sh/" + _url.lstrip("/")
    # Strip non-ASCII via encode/decode — avoids regex byte-escape issues
    _safe_title = title.encode("ascii", "ignore").decode("ascii").strip() or "RavenMiner Alert"
    def _post():
        try:
            resp = requests.post(
                _url,
                data=message.encode("utf-8"),
                headers={
                    "Title":        _safe_title,
                    "Priority":     priority,
                    "Tags":         tags,
                    "Content-Type": "text/plain; charset=utf-8",
                },
                timeout=6,
            )
            if resp.status_code not in (200, 201, 204):
                print(f"[RavenMiner] ntfy HTTP {resp.status_code}: {resp.text[:300]}")
        except Exception as ex:
            print("[RavenMiner] ntfy alert error:", ex)
    threading.Thread(target=_post, daemon=True).start()  # CR2-PERF-7: removed redundant `import threading as _th`

