# STYLE-05: hoisted from _draw_bars — no longer redefined at 30fps
_RAMP_COLOR_STOPS = [
    (5.8,  (231, 10,  0)),
    (6.2,  (40,  175, 255)),
    (6.35, (211, 50,  231)),
    (6.45, (50,  221, 57)),
    (6.6,  (255, 231, 45)),
]

def _ramp_color(v):
    """Map a hashrate value to an RGB colour tuple (module-level, STYLE-05)."""
    if v <= _RAMP_COLOR_STOPS[0][0]:  return _RAMP_COLOR_STOPS[0][1]
    if v >= _RAMP_COLOR_STOPS[-1][0]: return _RAMP_COLOR_STOPS[-1][1]
    for _i in range(len(_RAMP_COLOR_STOPS) - 1):
        v0, c0 = _RAMP_COLOR_STOPS[_i]
        v1, c1 = _RAMP_COLOR_STOPS[_i + 1]
        if v0 <= v <= v1:
            _ft = (v - v0) / (v1 - v0)
            _ft = _ft * _ft * (3 - 2 * _ft)  # smoothstep
            return tuple(int(c0[j] + (c1[j] - c0[j]) * _ft) for j in range(3))
    return _RAMP_COLOR_STOPS[-1][1]

# STYLE-02: hoisted from _build_right() — closure had no class dependencies
_GEAR_SIZE     = 130  # canvas + animation size
_GEAR_IMG_SIZE =  80  # gear image stays original size, centred in the larger canvas


def _catmull_rom_spline(pts, steps=10):
    """Expand (x,y) control points into a smooth Catmull-Rom spline.
    steps=10 → 10 sub-points per segment for very smooth curves.
    Returns a flat list [x0,y0, x1,y1, ...] suitable for tkinter create_line."""
    if len(pts) < 2:
        return [c for p in pts for c in p]
    # Duplicate endpoints so the spline passes through the first and last points
    p = [pts[0]] + list(pts) + [pts[-1]]
    out = []
    for i in range(1, len(p) - 2):
        x0, y0 = p[i - 1]
        x1, y1 = p[i]
        x2, y2 = p[i + 1]
        x3, y3 = p[i + 2]
        for s in range(steps):
            t  = s / steps
            t2 = t * t
            t3 = t2 * t
            x = 0.5 * ((2*x1) + (-x0 + x2)*t +
                        (2*x0 - 5*x1 + 4*x2 - x3)*t2 +
                        (-x0 + 3*x1 - 3*x2 + x3)*t3)
            y = 0.5 * ((2*y1) + (-y0 + y2)*t +
                        (2*y0 - 5*y1 + 4*y2 - y3)*t2 +
                        (-y0 + 3*y1 - 3*y2 + y3)*t3)
            out += [x, y]
    # Append the last control point
    out += list(pts[-1])
    return out

def _remove_white_bg(img, threshold=240, feather=15):
    """PERF-01: NumPy vectorised white-BG removal — <1 ms at any size.
    CR7-PERF-1: numpy imported at module level (see below) — per-call
    import lookup eliminated; function raises ImportError if numpy absent."""
    if not _NUMPY_OK:
        raise ImportError("numpy required for _remove_white_bg")
    if img.mode != "RGBA":
        img = img.convert("RGBA")
    arr = np.array(img, dtype=np.uint8)
    whiteness = arr[..., :3].min(axis=2)
    # Fully transparent where all channels >= threshold
    arr[whiteness >= threshold, 3] = 0
    # Feather the edge band
    feather_mask = (whiteness >= threshold - feather) & (whiteness < threshold)
    alpha_scale = ((threshold - whiteness[feather_mask]) / feather * 255).astype(np.uint8)
    arr[feather_mask, 3] = np.minimum(arr[feather_mask, 3], alpha_scale)
    return Image.fromarray(arr, "RGBA")


def _load_gear_images():
    """Decode GEAR_IMG_B64, apply white-BG removal, return (normal_photo, hover_photo)."""
    if not PIL_OK:
        return None, None
    try:
        raw = base64.b64decode(GEAR_IMG_B64)
        img = Image.open(io.BytesIO(raw)).convert("RGBA")
        img = _remove_white_bg(img, threshold=240, feather=20)
        img = img.resize((_GEAR_IMG_SIZE, _GEAR_IMG_SIZE), Image.LANCZOS)
        # normal — slight dim
        normal = img.copy()
        r2,g2,b2,a2 = normal.split()
        _lut_dim = [int(i*0.85) for i in range(256)]  # PERF-05: LUT replaces per-pixel lambda
        r2 = r2.point(_lut_dim)
        g2 = g2.point(_lut_dim)
        b2 = b2.point(_lut_dim)
        normal = Image.merge("RGBA",(r2,g2,b2,a2))
        return ImageTk.PhotoImage(normal), ImageTk.PhotoImage(img)
    except Exception as ex:
        print("Gear image load error:", ex)
        return None, None

def _load_gear_pil_images():
    """Return raw PIL RGBA images (normal-dim, hover-full) for per-frame rotation."""
    if not PIL_OK:
        return None, None
    try:
        raw  = base64.b64decode(GEAR_IMG_B64)
        img  = Image.open(io.BytesIO(raw)).convert("RGBA")
        img  = _remove_white_bg(img, threshold=240, feather=20)
        img  = img.resize((_GEAR_IMG_SIZE, _GEAR_IMG_SIZE), Image.LANCZOS)
        normal = img.copy()
        r2,g2,b2,a2 = normal.split()
        _lut = [int(i*0.85) for i in range(256)]
        normal = Image.merge("RGBA", (r2.point(_lut), g2.point(_lut), b2.point(_lut), a2))
        return normal, img          # normal-dim, hover-full
    except Exception:
        return None, None

