    def _init_valknut(self):
        base = load_valknut_base()
        if base is None:
            print("Valknut image failed to load")
            return
        STEPS = 16
        self.valk_frames = []
        for i in range(STEPS):
            factor = 1.0 - (i / STEPS) * (1.0 - 0.03)
            frame  = base.copy()
            r2,g2,b2,a2 = frame.split()
            new_a  = a2.point(lambda p, f=factor: int(p*f))
            frame.putalpha(new_a)
            self.valk_frames.append(frame)
        # v5.5.2: overbright flash frames — used only during share event
        self.valk_flash_frames = []
        FLASH_STEPS = 10
        from PIL import ImageEnhance as _IE
        for _fi in range(FLASH_STEPS):
            _t    = _fi / max(FLASH_STEPS - 1, 1)           # 0 → 1
            _peak = 0.45                                      # where the boost peaks (45% of the way in)
            _boost = 1.0 + 0.85 * (1.0 - abs((_t - _peak) / max(_peak, 1 - _peak)))
            _boost = max(1.0, _boost)
            _frm  = base.copy()
            _frm  = _IE.Brightness(_frm).enhance(_boost)
            _frm  = _IE.Color(_frm).enhance(1.0 + 0.5 * (1.0 - abs((_t - _peak) / max(_peak, 1 - _peak))))
            self.valk_flash_frames.append(_frm)
        print("Valknut ready:", len(self.valk_frames), "frames,", len(self.valk_flash_frames), "flash frames")
        self._show_valknut_frame(self.valk_frames[-1])

    def _show_valknut_frame(self, pil_img):
        # PATCH-WM4: eliminate all blank-frame flashes.
        # Core insight: Tkinter Canvas itemconfig(image=...) hot-swaps the image
        # in-place with zero visible gap.  delete("all") is now called ONLY on the
        # very first draw or after a canvas resize — never during animation frames.
        #
        # Flow:
        #   1. Build / retrieve cached composite PhotoImage (unchanged from before).
        #   2. If canvas items exist at the right size → itemconfig swap (no flash).
        #   3. Otherwise → one-time delete/create to establish the item IDs.
        cw = self.valk_canvas.winfo_width()  or 320
        ch = self.valk_canvas.winfo_height() or 340
        # Stable cache key: use vegvisir .size tuple, not id() of a copy
        _vvp = getattr(self, "_vegvisir_pil", None)
        _cache_key = (id(pil_img), cw, ch,
                      _vvp.size if _vvp is not None else None)
        _cache = getattr(self, "_valk_composite_cache", {})
        cached_photo = _cache.get(_cache_key)

        if cached_photo is None:
            # ── Cache MISS: build composite ──────────────────────────────────
            bg = Image.new("RGBA", (cw, ch), (9, 9, 18, 255))
            try:
                if _vvp is not None:
                    pw  = self._vegvisir_pw
                    ph  = self._vegvisir_ph
                    vsz = _vvp.size[0]
                    vx  = self.valk_canvas.winfo_rootx() - self.veg_canvas.winfo_rootx()
                    vy  = self.valk_canvas.winfo_rooty() - self.veg_canvas.winfo_rooty()
                    full = Image.new("RGBA", (pw, ph), (9, 9, 18, 255))
                    ox   = pw // 2 - vsz // 2
                    oy   = ph // 2 - vsz // 2
                    full.paste(_vvp, (ox, oy), _vvp)
                    crop = full.crop((vx, vy, vx + cw, vy + ch))
                    bg   = Image.alpha_composite(bg, crop)
            except Exception:
                pass
            # ── Gold ravens: composite into bg corners (LARGER @ 30%) ──
            try:
                _rs = int(min(cw, ch) * 0.30)
                if _rs >= 40:
                    global _RAVEN_L_PIL_CACHE, _RAVEN_R_PIL_CACHE
                    if _RAVEN_L_PIL_CACHE is None:
                        _RAVEN_L_PIL_CACHE = Image.open(
                            io.BytesIO(base64.b64decode(RAVEN_L_B64))).convert("RGBA")
                    if _RAVEN_R_PIL_CACHE is None:
                        _RAVEN_R_PIL_CACHE = Image.open(
                            io.BytesIO(base64.b64decode(RAVEN_R_B64))).convert("RGBA")
                    def _gr(im):
                        al = im.split()[3].point(lambda p: min(255, int(p * 0.92)))
                        o  = Image.new("RGBA", im.size, (240, 192, 48, 255))
                        o.putalpha(al); return o
                    _rl = _gr(_RAVEN_L_PIL_CACHE.resize((_rs, _rs), Image.LANCZOS))
                    _rr = _gr(_RAVEN_R_PIL_CACHE.resize((_rs, _rs), Image.LANCZOS))
                    _xm = _rs // 2 + 8
                    _yp = _rs // 2 + 8
                    bg.paste(_rl, (_xm - _rs // 2, _yp - _rs // 2), _rl)
                    bg.paste(_rr, (cw - _xm - _rs // 2, _yp - _rs // 2), _rr)
            except Exception as _re:
                print("Raven composite error:", _re)
            _sq   = min(cw, ch)          # FIX: fit within both axes
            _ox   = (cw - _sq) // 2      # FIX: horizontal centre
            _oy   = (ch - _sq) // 2      # FIX: vertical centre
            _vsq  = pil_img.resize((_sq, _sq), Image.LANCZOS)
            valk  = Image.new("RGBA", (cw, ch), (0, 0, 0, 0))
            valk.paste(_vsq, (_ox, _oy), _vsq)  # FIX: centred paste
            result = Image.alpha_composite(bg, valk)
            cached_photo = ImageTk.PhotoImage(result)
            if len(_cache) >= 32:
                _cache.clear()
            _cache[_cache_key]       = cached_photo
            self._valk_composite_cache = _cache

        # ── Draw (or update) canvas items ────────────────────────────────────
        self.valk_photo              = cached_photo
        self.valk_canvas.valk_photo  = cached_photo
        _ht = getattr(self, "_hr_text_val", "--")
        _hc = getattr(self, "_hr_text_col", PURPLE_GLOW)

        _img_id  = getattr(self.valk_canvas, "_wm_img_id",  None)
        _prev_cw = getattr(self.valk_canvas, "_wm_cw",      None)
        _prev_ch = getattr(self.valk_canvas, "_wm_ch",      None)

        if _img_id and _prev_cw == cw and _prev_ch == ch:
            # ── FAST PATH: hot-swap — zero blank frames ───────────────────────
            try:
                self.valk_canvas.itemconfig(_img_id, image=cached_photo)
                if self._hr_text_id:
                    self.valk_canvas.itemconfig(self._hr_text_id, text=_ht, fill=_hc)
                if self._hr_unit_id:
                    self.valk_canvas.itemconfig(self._hr_unit_id, text="TH/s")
                return
            except Exception:
                pass  # items stale — fall through to full create

        # ── SLOW PATH: first draw or canvas resized (rare) ───────────────────
        # FIX-FLASH: when items already exist (resize case), update in-place
        # via itemconfig + coords so the canvas is NEVER blank for even one frame.
        # delete("all") is only reached on the very first draw when the canvas
        # is guaranteed to be empty — no visible flash possible there.
        if _img_id:
            try:
                self.valk_canvas.itemconfig(_img_id, image=cached_photo)
                self.valk_canvas.coords(_img_id, cw // 2, ch // 2)
                if self._hr_text_id:
                    self.valk_canvas.itemconfig(self._hr_text_id, text=_ht, fill=_hc)
                    self.valk_canvas.coords(self._hr_text_id, cw // 2, ch - 70)
                if self._hr_unit_id:
                    self.valk_canvas.coords(self._hr_unit_id, cw // 2, ch - 22)
                self.valk_canvas._wm_cw = cw
                self.valk_canvas._wm_ch = ch
                return
            except Exception:
                pass  # items truly stale — fall through to fresh create
        # First-ever draw: canvas is empty, safe to create without deleting
        self.valk_canvas.delete("all")
        _img_id = self.valk_canvas.create_image(
            cw // 2, ch // 2, image=cached_photo, anchor="center")
        self._hr_text_id = self.valk_canvas.create_text(
            cw // 2, ch - 70, text=_ht,
            font=("Courier", 72, "bold"), fill=_hc, anchor="center")
        self._hr_unit_id = self.valk_canvas.create_text(
            cw // 2, ch - 22, text="TH/s",
            font=("Courier", 20), fill=GOLD, anchor="center")
        self.valk_canvas._wm_img_id = _img_id
        self.valk_canvas._wm_cw     = cw
        self.valk_canvas._wm_ch     = ch

    def _trigger_valknut_flash(self):
        if self.valk_flash or not self.valk_frames:
            return
        self.valk_flash      = True
        self.valk_step       = 0
        self._use_flash_seq  = True   # v5.5.2: overbright sequence on share
        self._valknut_next_frame()
        self.root.after(0, self._flash_ravens)  # v3.9.3: ravens brighten on share

    def _valknut_next_frame(self):
        # v5.5.2: choose overbright flash frames during share event
        _seq = (self.valk_flash_frames
                if getattr(self, '_use_flash_seq', False)
                   and getattr(self, 'valk_flash_frames', None)
                else self.valk_frames)
        if self.valk_step < len(_seq):
            self._show_valknut_frame(_seq[self.valk_step])
            self.valk_step += 1
            self.root.after(50, self._valknut_next_frame)
        else:
            self.valk_flash     = False
            self.valk_step      = 0
            self._use_flash_seq = False
            self._show_valknut_frame(self.valk_frames[-1])  # PERF-03: frames pre-rendered at init

    def _draw_vegvisir_bg(self):
        raise NotImplementedError(
            "_draw_vegvisir_bg() is deprecated — use _draw_vegvisir_centre() instead.")


    # PERF-04: keyed on (raven_size, side) — LANCZOS only fires when size changes
    _RAVEN_RESIZED_CACHE: dict = {}

    def _draw_raven_pair(self, canvas, pw, ph):
        """Gold ravens flanking the Vegvisir watermark on veg_canvas."""
        global _RAVEN_L_PIL_CACHE, _RAVEN_R_PIL_CACHE
        if not PIL_OK:
            return
        raven_size = int(min(pw, ph) * 0.19)
        if raven_size < 40:
            return
        try:
            if _RAVEN_L_PIL_CACHE is None:
                _RAVEN_L_PIL_CACHE = Image.open(io.BytesIO(base64.b64decode(RAVEN_L_B64))).convert("RGBA")
            if _RAVEN_R_PIL_CACHE is None:
                _RAVEN_R_PIL_CACHE = Image.open(io.BytesIO(base64.b64decode(RAVEN_R_B64))).convert("RGBA")
            _lkey, _rkey = (raven_size, "L"), (raven_size, "R")  # PERF-04
            if _lkey not in RavenMinerDash._RAVEN_RESIZED_CACHE:
                RavenMinerDash._RAVEN_RESIZED_CACHE[_lkey] = _RAVEN_L_PIL_CACHE.resize((raven_size, raven_size), Image.LANCZOS)
            if _rkey not in RavenMinerDash._RAVEN_RESIZED_CACHE:
                RavenMinerDash._RAVEN_RESIZED_CACHE[_rkey] = _RAVEN_R_PIL_CACHE.resize((raven_size, raven_size), Image.LANCZOS)
            # CR2-PERF-5: Evict oldest entries if cache exceeds 32 (entries come in L/R pairs)
            while len(RavenMinerDash._RAVEN_RESIZED_CACHE) > 32:
                _oldest = next(iter(RavenMinerDash._RAVEN_RESIZED_CACHE))
                del RavenMinerDash._RAVEN_RESIZED_CACHE[_oldest]
            rl = RavenMinerDash._RAVEN_RESIZED_CACHE[_lkey].copy()  # CR2-BUG-1: .copy() prevents in-place putalpha from corrupting the cache
            rr = RavenMinerDash._RAVEN_RESIZED_CACHE[_rkey].copy()  # CR2-BUG-1: same fix
            # Mirror left raven to face outward (leftward) — Huginn & Muninn fly outward
            rl = rl.transpose(Image.FLIP_LEFT_RIGHT)  # left corner faces right
            # rr unchanged — b64 already faces left toward middle
            # v3.9.3: use natural alpha — no opacity reduction, background is transparent
            # apply alpha softness — must reassign since putalpha mutates in-place
            def _goldify(img):
                alp = img.split()[3].point(lambda p: min(255, int(p * 0.92)))
                out = Image.new("RGBA", img.size, (240, 192, 48, 255))
                out.putalpha(alp); return out
            rl = _goldify(rl)
            rr = _goldify(rr)
            rl = rl.convert("RGBA")
            rr = rr.convert("RGBA")
            x_margin = raven_size // 2 + 10
            y_pos    = raven_size // 2 + 62  # v5.2.1: lowered 24px from v5.0.4 (+38) so ravens clear the top bar
            canvas.delete("ravens")
            self._raven_l_photo = ImageTk.PhotoImage(rl.convert("RGBA"))
            self._raven_r_photo = ImageTk.PhotoImage(rr.convert("RGBA"))
            canvas.create_image(x_margin,        y_pos, image=self._raven_l_photo, anchor="center", tags="ravens")
            canvas.create_image(pw - x_margin,   y_pos, image=self._raven_r_photo, anchor="center", tags="ravens")
            canvas.tag_lower("ravens")
            canvas.tag_raise("vegvisir_img")
        except Exception as e:
            print("Raven draw error:", e)

    def _flash_ravens(self, step=0, steps=16):
        """Blazing gold-white raven flash on share accepted — drawn on valk_canvas."""
        if not PIL_OK:
            return
        canvas = self.valk_canvas  # VISIBLE canvas — on top of everything
        cw = canvas.winfo_width()  or 320
        ch = canvas.winfo_height() or 340
        if cw < 10 or ch < 10:
            return
        global _RAVEN_L_PIL_CACHE, _RAVEN_R_PIL_CACHE
        try:
            if _RAVEN_L_PIL_CACHE is None or _RAVEN_R_PIL_CACHE is None:
                return
            raven_size = int(min(cw, ch) * 0.30)  # v3.9.3: same size as normal
            if raven_size < 40:
                return
            # v3.9.3: 50% reduced brightness — ease curve capped at 0.675 peak
            PEAK_BRIGHTNESS = 1.0   # v5.5.2: full blaze on share (was 0.675)
            peak = steps // 3
            if step <= peak:
                t = step / max(peak, 1)
                brightness = 0.35 + (PEAK_BRIGHTNESS - 0.35) * (t * t * (3 - 2 * t))
            else:
                t = (step - peak) / max(steps - 1 - peak, 1)
                brightness = PEAK_BRIGHTNESS - (PEAK_BRIGHTNESS - 0.35) * (t * t)
            brightness = max(0.35, min(PEAK_BRIGHTNESS, brightness))

            # Gold glow intensity — peaks at 90 (50% of original 180)
            glow = int((brightness - 0.35) / (PEAK_BRIGHTNESS - 0.35) * 160)  # v5.5.2: brighter glow on share

            # Resize from cache — b64 images already face correct directions
            _fkey = (raven_size, "flash")
            if not hasattr(self, "_raven_flash_base") or self._raven_flash_base[0] != _fkey:
                _rl_b = _RAVEN_L_PIL_CACHE.resize((raven_size, raven_size), Image.LANCZOS)
                _rr_b = _RAVEN_R_PIL_CACHE.resize((raven_size, raven_size), Image.LANCZOS)
                self._raven_flash_base = (_fkey, _rl_b, _rr_b)
            rl = self._raven_flash_base[1].copy()
            rr = self._raven_flash_base[2].copy()

            flash_imgs = []
            for _img in (rl, rr):
                # Brilliant gold→white blaze — paint over black silhouette
                _br = min(255, int(240 * brightness) + glow)
                _bg_c = min(255, int(192 * brightness) + int(glow * 0.82))
                _bb = min(255, int(48  * brightness) + int(glow * 0.35))
                _a  = _img.split()[3].point(
                    lambda p: 0 if p == 0 else min(255, int(p * 2.8 * brightness + glow * 0.5)))
                _gf = Image.new("RGBA", _a.size, (_br, _bg_c, _bb, 255))
                _gf.putalpha(_a)
                flash_imgs.append(_gf)

            _xm = raven_size // 2 + 8
            _yp = raven_size // 2 + 8
            canvas.delete("raven_flash")
            self._raven_flash_l = ImageTk.PhotoImage(flash_imgs[0])
            self._raven_flash_r = ImageTk.PhotoImage(flash_imgs[1])
            canvas.create_image(_xm,        _yp, image=self._raven_flash_l, anchor="center", tags="raven_flash")
            canvas.create_image(cw - _xm,   _yp, image=self._raven_flash_r, anchor="center", tags="raven_flash")
            canvas.tag_raise("raven_flash")  # ABOVE background image — fully visible

            if step < steps - 1:
                self.root.after(40, lambda: self._flash_ravens(step + 1, steps))
            else:
                canvas.delete("raven_flash")  # clean up after animation
        except Exception as e:
            print("Raven flash error:", e)


    def _build_avg_canvas_boxes(self):
        c=self.veg_canvas; cw=c.winfo_width()
        if not hasattr(self,"_avg_top_div"): return
        dy=self._avg_top_div.winfo_y()+2
        if cw<10 or dy<2: self.root.after(100,self._build_avg_canvas_boxes); return
        c.delete("avg_boxes")
        BH,BW=72,175
        cy=dy+6
        for x,lbl,aid in [
            (30,"1m AVG","_avg_1m_id"),
            (cw//2-BW//2,"10m AVG","_avg_10m_id"),
            (cw-30-BW,"1h AVG","_avg_1h_id")]:
            c.create_rectangle(x,cy,x+BW,cy+BH,outline=GOLD,fill="",width=1,tags="avg_boxes")
            c.create_text(x+BW//2,cy+18,text=lbl,fill=GOLD,font=("Courier",12),tags="avg_boxes")
            vid=c.create_text(x+BW//2,cy+48,text="--",fill=GOLD,font=("Courier",20,"bold"),tags="avg_boxes")
            setattr(self,aid,vid)
        try: c.tag_raise("avg_boxes","vegvisirimg")
        except Exception: pass
        c.bind("<Configure>",lambda e:self.root.after(60,self._build_avg_canvas_boxes),add="+")

    def _draw_vegvisir_centre(self, parent):

        global _VEGVISIR_PIL_CACHE
        if not PIL_OK:
            return
        try:
            pw = parent.winfo_width()
            ph = parent.winfo_height()
            if pw < 10:  # not rendered yet, retry
                parent.after(300, lambda: self._draw_vegvisir_centre(parent))
                return
            # PATCH-WM1: skip rebuild when size is identical — keeps _vegvisir_pil
            # object identity stable so the composite cache key never busts spuriously.
            if (getattr(self, '_vegvisir_pw', None) == pw
                    and getattr(self, '_vegvisir_ph', None) == ph
                    and getattr(self, '_vegvisir_pil', None) is not None):
                return
            if _VEGVISIR_PIL_CACHE is None:
                raw = base64.b64decode(VEGVISIR_B64)
                buf = io.BytesIO(raw)
                buf.seek(0)
                _VEGVISIR_PIL_CACHE = Image.open(buf).convert("RGBA")
            img = _VEGVISIR_PIL_CACHE.copy()
            # 40% opacity watermark
            r2,g2,b2,a2 = img.split()
            a2 = a2.point(lambda p: int(p * 0.35))
            img.putalpha(a2)
            # AFTER — dynamically fills ~85% of the smaller panel dimension
            size = int(min(pw, ph) * 0.85)
            _SS = 2  # supersampling factor — render 2× then downscale for crisp AA
            img = img.resize((size * _SS, size * _SS), Image.LANCZOS)
            img = img.resize((size, size), Image.LANCZOS)

            # Cache PIL for valknut compositing
            self._vegvisir_pil = img
            self._vegvisir_pw  = pw
            self._vegvisir_ph  = ph
            photo = ImageTk.PhotoImage(img)
            self._vegvisir_photo = photo
            self.veg_canvas.veg_photo = photo
            # FIX-FLASH: itemconfig in-place to avoid blank frame on resize
            _vv_id = getattr(self.veg_canvas, "_vv_item_id", None)
            if _vv_id and self.veg_canvas.find_withtag("vegvisir_img"):
                self.veg_canvas.itemconfig(_vv_id, image=photo)
                self.veg_canvas.coords(_vv_id, pw // 2, ph // 2)
            else:
                _vv_id = self.veg_canvas.create_image(
                    pw // 2, ph // 2, image=photo, anchor="center", tags="vegvisir_img")
                self.veg_canvas._vv_item_id = _vv_id
                self.veg_canvas.tag_lower("vegvisir_img")
                if self.veg_canvas.find_withtag("valknut"):
                    self.veg_canvas.tag_raise("valknut")
            # Draw gold ravens flanking the watermark
            self._draw_raven_pair(self.veg_canvas, pw, ph)
            # PATCH-WM4b: pre-warm valk_canvas composite so the cache is hot
            # before the first share flash — avoids a cold-miss redraw later.
            if getattr(self, "valk_frames", None):
                self.root.after(0, lambda: self._show_valknut_frame(self.valk_frames[-1]))
        except Exception as e:
            print("Vegvisir centre error:", e)

