        self._divider(p)
        self._stat_block(p,"FREQUENCY","--","MHz",CYAN,"lbl_freq",COL_R)
        self._divider(p)
        self._stat_block(p,"CORE VOLT","--","mV",PURPLE_GLOW,"lbl_vcore",COL_R)
